import React, { Fragment } from "react";
import { Jumbotron, Container, Row, Col } from "react-bootstrap";

const Skills = ({skillsSection}) => {
  return (
    <Jumbotron fluid className="bg-white m-0" id="skills">
      <Container className="text-center my-5 section section-lg">
      <div
        className="bg-warning shadow rounded-circle mb-5" style={{ width: "50px", height: "50px" }}
      >
        <Row className="justify-content-md-center">
          <span><i class="fab fa-python" style={{color: "White", fontSize: "2rem", paddingTop: "0.5rem"}}></i></span>
        </Row>
      </div>
			</Container>
    </Jumbotron>
  );
}

export default Skills;
